import React from 'react';
import { Link } from 'react-router-dom';
import { motion } from 'framer-motion';

export default function OurSolution() {
  return (
    <section style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', paddingTop: 68 }}>
      <div className="container" style={{ textAlign: 'center', paddingTop: 80, paddingBottom: 80 }}>
        <motion.p
          className="section-eyebrow"
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ duration: 0.5 }}
        >
          Our Solution
        </motion.p>
        <motion.h1
          style={{ fontSize: 'clamp(32px, 4.5vw, 50px)', fontWeight: 800, letterSpacing: '-1.5px', marginBottom: 20 }}
          initial={{ opacity: 0, y: 24 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6, delay: 0.1 }}
        >
          Four pillars. One trusted{' '}
          <span className="accent">custody chain.</span>
        </motion.h1>
        <motion.p
          className="section-subtext"
          style={{ margin: '0 auto 36px' }}
          initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.6, delay: 0.2 }}
        >
          Complete verification from pickup through delivery — without slowing operations.
          Full page coming soon.
        </motion.p>
        <motion.div
          initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.35 }}
        >
          <Link to="/join" className="btn-primary">Join the Pilot Program</Link>
        </motion.div>
      </div>
    </section>
  );
}
